/**
 * Renders a single task card HTML.
 * @param {Task} task
 * @param {string} id
 * @returns {string}
 */
function renderTasksHTML(task, id) {
  const priorityClass = filterPriority(task.priority);
  const categoryClass = filterCategory(task.category);
  return `
    <div class="cards" data-id="${id}" draggable="true">
      <!-- Card content generated by template functions -->
      ${buildCardHeader(task, categoryClass)}
      ${buildCardTitle(task.title)}
      ${buildCardDescription(task.description)}
      ${buildCardProgress(task)}
      ${buildCardFooter(task, priorityClass, id)}
    </div>
  `;
}

/**
 * Builds card header with category badge.
 * @param {Task} task
 * @param {string} categoryClass
 * @returns {string}
 */
function buildCardHeader(task, categoryClass) {
  return `<div class="card-category ${categoryClass}">${task.category}</div>`;
}

/**
 * Builds card title element.
 * @param {string} title
 * @returns {string}
 */
function buildCardTitle(title) {
  return `<h3 class="card-title">${title || ""}</h3>`;
}

/**
 * Builds card description element.
 * @param {string} description
 * @returns {string}
 */
function buildCardDescription(description) {
  return `<p class="card-desc">${description || ""}</p>`;
}

/**
 * Builds progress bar for subtasks.
 * @param {Task} task
 * @returns {string}
 */
function buildCardProgress(task) {
  const { total, checked } = getSubtaskStats(task);
  if (total === 0) return "";

  const percent = Math.round((checked / total) * 100);
  return `<div class="progress"><div style="width:${percent}%"></div></div>`;
}

/**
 * Builds card footer with priority, avatars and date.
 * @param {Task} task
 * @param {string} priorityClass
 * @param {string} id
 * @returns {string}
 */
function buildCardFooter(task, priorityClass, id) {
  return `
    <div class="card-footer">
      <span class="priority ${priorityClass}">${task.priority}</span>
      <div class="avatars">${renderTaskContact(task.contacts)}</div>
      <span class="due-date">${dateStringChange(task.duedate)}</span>
      <button onclick="openTaskDetailsOverlay(this)" data-id="${id}">
        Details
      </button>
    </div>
  `;
}

/**
 * Renders a single contact avatar.
 * @param {Contact} contact
 * @returns {string}
 */
function renderContactAvatarHTML(contact) {
  const initials = getInitials(contact.name);
  return `<div class="avatar" title="${contact.name}">${initials}</div>`;
}

/**
 * Extracts initials from a full name.
 * @param {string} name
 * @returns {string}
 */
function getInitials(name) {
  if (!name) return "?";
  const parts = name.trim().split(" ");
  return parts
    .slice(0, 2)
    .map((p) => p[0])
    .join("")
    .toUpperCase();
}

/**
 * Template for task popup details.
 * @param {Task} task
 * @param {string} id
 * @returns {string}
 */
function taskPopup(task, id) {
  return `
    <div class="task-popup">
      ${buildPopupHeader(task, id)}
      ${buildPopupBody(task, id)}
      ${buildPopupFooter(id)}
    </div>
  `;
}

/**
 * Builds popup header section.
 * @param {Task} task
 * @param {string} id
 * @returns {string}
 */
function buildPopupHeader(task, id) {
  return `
    <div class="popup-header">
      <h2>${task.title}</h2>
      <button onclick="closetaskDetailsOverlay()">✕</button>
    </div>
  `;
}

/**
 * Builds popup body with details.
 * @param {Task} task
 * @param {string} id
 * @returns {string}
 */
function buildPopupBody(task, id) {
  return `
    <div class="popup-body">
      <p>${task.description}</p>
      <div id="SubtaskList">${renderTaskSubTaskDetails(id)}</div>
      <div class="contacts">${renderTaskContactDetails(task.contacts)}</div>
    </div>
  `;
}

/**
 * Builds popup footer with actions.
 * @param {string} id
 * @returns {string}
 */
function buildPopupFooter(id) {
  return `
    <div class="popup-footer">
      <button onclick="editTaskOnBoard('${id}')">Edit</button>
      <button onclick="deleteTaskOnBoard('${id}')">Delete</button>
    </div>
  `;
}

/**
 * Template for edit mode popup.
 * @param {Task} task
 * @param {string} id
 * @returns {string}
 */
function taskPopupEditMode(task, id) {
  return `
    <div class="task-popup edit-mode">
      ${buildEditForm(task, id)}
    </div>
  `;
}

/**
 * Builds the edit form HTML.
 * @param {Task} task
 * @param {string} id
 * @returns {string}
 */
function buildEditForm(task, id) {
  return `
    <form id="editTaskForm" onsubmit="saveEditedTask('${id}'); return false;">
      <input type="text" id="title" value="${task.title}">
      <textarea id="description">${task.description}</textarea>
      <input type="date" id="duedate" value="${task.duedate}">
      ${buildPriorityRadio(task.priority)}
      ${buildCategorySelect(task.category)}
      <div id="SubtaskList"></div>
      <button type="submit">Save</button>
      <button type="button" onclick="closetaskDetailsOverlay()">Cancel</button>
    </form>
  `;
}

/**
 * Builds priority radio buttons.
 * @param {string} current
 * @returns {string}
 */
function buildPriorityRadio(current) {
  return `
    <div class="priority-group">
      <label><input type="radio" name="priority" value="low" ${current === "low" ? "checked" : ""}> Low</label>
      <label><input type="radio" name="priority" value="medium" ${current === "medium" ? "checked" : ""}> Medium</label>
      <label><input type="radio" name="priority" value="urgent" ${current === "urgent" ? "checked" : ""}> Urgent</label>
    </div>
  `;
}

/**
 * Builds category select dropdown.
 * @param {string} current
 * @returns {string}
 */
function buildCategorySelect(current) {
  return `
    <select name="priorityCategory" id="priorityCategory">
      <option value="Technical Task" ${current === "Technical Task" ? "selected" : ""}>Technical Task</option>
      <option value="User Story" ${current === "User Story" ? "selected" : ""}>User Story</option>
    </select>
  `;
}

